     1→<!DOCTYPE html>
     2→<html lang="en">
     3→<head>
     4→<meta charset="UTF-8">
     5→<meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→<title>Technical Hackathons — Habitat</title>
     7→<link rel="icon" type="image/svg+xml" href="favicon.svg">
     8→<meta name="description" content="Full-day technical builds for developers and founders. Team-based, expertly-judged. Build something that matters.">
     9→<link rel="preconnect" href="https://fonts.googleapis.com">
    10→<link href="https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&family=Outfit:wght@300;400;500;600;700&display=swap" rel="stylesheet">
    11→<script defer src="/_vercel/insights/script.js"></script>
    12→<style>
    13→:root {
    14→  --bg: #fafaf8;
    15→  --text: #1c1b1a;
    16→  --cream: #f0ede6;
    17→  --gray: #6b6864;
    18→  --gray-light: #8a8780;
    19→  --accent: #3d5afc;
    20→  --accent-glow: #2d4ae8;
    21→  --coral: #e85a35;
    22→  --teal: #16b889;
    23→  --purple: #7c4fcc;
    24→  --font-display: 'Space Mono', monospace;
    25→  --font-body: 'Outfit', sans-serif;
    26→}
    27→
    28→*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
    29→html { scroll-behavior: smooth; }
    30→body {
    31→  font-family: var(--font-body);
    32→  background: var(--bg);
    33→  color: var(--text);
    34→  line-height: 1.6;
    35→  overflow-x: hidden;
    36→  -webkit-font-smoothing: antialiased;
    37→}
    38→a { color: inherit; text-decoration: none; }
    39→img { max-width: 100%; display: block; }
    40→
    41→.container { max-width: 1200px; margin: 0 auto; padding: 0 24px; }
    42→section { padding: 120px 0; }
    43→
    44→/* NAV */
    45→nav {
    46→  position: fixed; top: 0; left: 0; right: 0; z-index: 100;
    47→  padding: 20px 0;
    48→  background: rgba(250,250,248,0.92);
    49→  backdrop-filter: blur(20px);
    50→  border-bottom: 1px solid rgba(28,27,26,0.08);
    51→}
    52→nav .container { display: flex; align-items: center; justify-content: space-between; }
    53→.logo { font-family: var(--font-display); font-size: 18px; font-weight: 700; letter-spacing: -0.5px; }
    54→
    55→.nav-links { display: flex; gap: 32px; align-items: center; list-style: none; }
    56→.nav-links a { font-size: 14px; font-weight: 400; color: var(--gray); transition: color 0.2s; }
    57→.nav-links a:hover { color: var(--text); }
    58→.nav-links a.active { color: var(--accent); font-weight: 500; }
    59→.nav-cta {
    60→  background: var(--accent); color: #ffffff !important;
    61→  padding: 10px 24px; border-radius: 6px;
    62→  font-weight: 600; font-size: 14px; transition: background 0.2s;
    63→}
    64→.nav-cta:hover { background: var(--accent-glow) !important; }
    65→
    66→/* HERO */
    67→.hero {
    68→  min-height: 80vh; display: flex; align-items: center;
    69→  padding-top: 100px; position: relative;
    70→}
    71→.hero::before {
    72→  content: ''; position: absolute; top: -100px; right: -200px;
    73→  width: 600px; height: 600px;
    74→  background: radial-gradient(circle, rgba(61,90,252,0.07) 0%, transparent 70%);
    75→  pointer-events: none;
    76→}
    77→.hero-badge {
    78→  display: inline-flex; align-items: center; gap: 8px;
    79→  font-family: var(--font-display); font-size: 11px;
    80→  letter-spacing: 1.5px; text-transform: uppercase;
    81→  background: rgba(61,90,252,0.1); color: var(--accent);
    82→  padding: 6px 14px; border-radius: 4px; margin-bottom: 24px;
    83→}
    84→.hero-label {
    85→  font-family: var(--font-display); font-size: 13px;
    86→  color: var(--accent); letter-spacing: 2px; text-transform: uppercase;
    87→  margin-bottom: 24px; display: flex; align-items: center; gap: 12px;
    88→}
    89→.hero-label::before { content: ''; width: 40px; height: 1px; background: var(--accent); }
    90→.hero h1 {
    91→  font-size: clamp(48px, 7vw, 76px); font-weight: 700;
    92→  line-height: 1.05; letter-spacing: -2px; margin-bottom: 28px;
    93→}
    94→.hero h1 em { font-style: normal; color: var(--accent); }
    95→.hero-sub {
    96→  font-size: 20px; color: var(--gray); max-width: 560px;
    97→  line-height: 1.6; margin-bottom: 48px; font-weight: 300;
    98→}
    99→.hero-meta {
   100→  display: flex; gap: 32px; flex-wrap: wrap; margin-bottom: 48px;
   101→}
   102→.hero-meta-item {
   103→  display: flex; flex-direction: column; gap: 4px;
   104→}
   105→.hero-meta-label { font-size: 12px; color: var(--gray); text-transform: uppercase; letter-spacing: 1px; }
   106→.hero-meta-value { font-family: var(--font-display); font-size: 16px; font-weight: 700; }
   107→.hero-buttons { display: flex; gap: 16px; flex-wrap: wrap; }
   108→.btn-primary {
   109→  display: inline-flex; align-items: center; gap: 8px;
   110→  background: var(--accent); color: #ffffff;
   111→  padding: 16px 32px; border-radius: 8px;
   112→  font-weight: 600; font-size: 16px;
   113→  transition: all 0.2s; border: none; cursor: pointer;
   114→}
   115→.btn-primary:hover { background: var(--accent-glow); transform: translateY(-1px); }
   116→.btn-secondary {
   117→  display: inline-flex; align-items: center; gap: 8px;
   118→  background: transparent; color: var(--text);
   119→  padding: 16px 32px; border-radius: 8px;
   120→  font-weight: 500; font-size: 16px;
   121→  border: 1px solid rgba(28,27,26,0.18); transition: all 0.2s; cursor: pointer;
   122→}
   123→.btn-secondary:hover { border-color: rgba(28,27,26,0.35); background: rgba(28,27,26,0.04); }
   124→
   125→/* FORMAT SECTION */
   126→.format-section { background: var(--cream); }
   127→.section-label {
   128→  font-family: var(--font-display); font-size: 13px;
   129→  color: var(--accent); letter-spacing: 2px; text-transform: uppercase; margin-bottom: 16px;
   130→}
   131→.section-title {
   132→  font-size: clamp(36px, 5vw, 56px); font-weight: 700;
   133→  letter-spacing: -1.5px; margin-bottom: 16px; line-height: 1.1;
   134→}
   135→.section-sub { font-size: 18px; color: var(--gray); max-width: 600px; margin-bottom: 64px; font-weight: 300; }
   136→
   137→.timeline {
   138→  display: flex; flex-direction: column; gap: 0;
   139→  max-width: 720px; margin-top: 64px;
   140→}
   141→.timeline-item {
   142→  display: flex; gap: 32px; position: relative; padding-bottom: 40px;
   143→}
   144→.timeline-item:last-child { padding-bottom: 0; }
   145→.timeline-time {
   146→  font-family: var(--font-display); font-size: 14px;
   147→  color: var(--accent); min-width: 80px; padding-top: 2px;
   148→}
   149→.timeline-dot {
   150→  display: flex; flex-direction: column; align-items: center; gap: 0;
   151→}
   152→.timeline-dot-circle {
   153→  width: 12px; height: 12px; border-radius: 50%;
   154→  background: var(--accent); flex-shrink: 0; margin-top: 6px;
   155→}
   156→.timeline-dot-line {
   157→  width: 1px; background: rgba(28,27,26,0.12);
   158→  flex: 1; margin-top: 4px;
   159→}
   160→.timeline-item:last-child .timeline-dot-line { display: none; }
   161→.timeline-content { flex: 1; }
   162→.timeline-content h3 { font-size: 18px; font-weight: 600; margin-bottom: 6px; }
   163→.timeline-content p { font-size: 15px; color: var(--gray); line-height: 1.6; }
   164→
   165→/* WHO SECTION */
   166→.who-grid {
   167→  display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
   168→  gap: 24px; margin-top: 64px;
   169→}
   170→.who-card {
   171→  background: #ffffff; border: 1px solid rgba(28,27,26,0.08);
   172→  border-radius: 16px; padding: 32px;
   173→  box-shadow: 0 1px 4px rgba(28,27,26,0.04);
   174→}
   175→.who-card-icon {
   176→  font-size: 28px; margin-bottom: 16px;
   177→}
   178→.who-card h3 { font-size: 18px; font-weight: 600; margin-bottom: 8px; }
   179→.who-card p { font-size: 14px; color: var(--gray); line-height: 1.6; }
   180→
   181→/* SPONSORS SECTION */
   182→.sponsors-section { background: var(--cream); }
   183→.sponsor-grid {
   184→  display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
   185→  gap: 32px; margin-top: 64px;
   186→}
   187→.sponsor-card {
   188→  background: #ffffff; border: 1px solid rgba(28,27,26,0.08);
   189→  border-radius: 16px; padding: 36px 32px;
   190→  box-shadow: 0 1px 4px rgba(28,27,26,0.04);
   191→}
   192→.sponsor-label {
   193→  font-family: var(--font-display); font-size: 11px;
   194→  letter-spacing: 1.5px; text-transform: uppercase;
   195→  color: var(--accent); margin-bottom: 16px;
   196→}
   197→.sponsor-card h3 { font-size: 20px; font-weight: 600; margin-bottom: 12px; }
   198→.sponsor-card p { font-size: 15px; color: var(--gray); line-height: 1.7; }
   199→.sponsor-card ul { list-style: none; margin-top: 20px; display: flex; flex-direction: column; gap: 8px; }
   200→.sponsor-card ul li {
   201→  font-size: 14px; color: var(--gray); display: flex; align-items: center; gap: 10px;
   202→}
   203→.sponsor-card ul li::before { content: '→'; color: var(--accent); font-size: 12px; }
   204→
   205→/* OUTPUT SECTION */
   206→.output-grid {
   207→  display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
   208→  gap: 48px; margin-top: 64px;
   209→}
   210→.output-item h3 { font-size: 20px; font-weight: 600; margin-bottom: 10px; letter-spacing: -0.3px; }
   211→.output-item p { font-size: 15px; color: var(--gray); line-height: 1.7; }
   212→.output-accent { width: 32px; height: 3px; margin-bottom: 20px; border-radius: 2px; background: var(--accent); }
   213→
   214→/* FAQ SECTION */
   215→.faq-section {
   216→  padding: 120px 0;
   217→  background: #ffffff;
   218→  border-top: 1px solid rgba(28,27,26,0.06);
   219→}
   220→.faq-container { max-width: 760px; margin: 0 auto; }
   221→.faq-category {
   222→  font-family: var(--font-display); font-size: 13px;
   223→  color: var(--accent); text-transform: uppercase;
   224→  letter-spacing: 2px; margin: 60px 0 24px 0; font-weight: 600;
   225→}
   226→.faq-category:first-of-type { margin-top: 0; }
   227→.faq-item { border-bottom: 1px solid rgba(28,27,26,0.08); }
   228→.faq-item details { width: 100%; }
   229→.faq-item summary {
   230→  display: flex; justify-content: space-between; align-items: center;
   231→  padding: 24px 0; font-size: 18px; font-weight: 500;
   232→  letter-spacing: -0.3px; color: var(--text); cursor: pointer; list-style: none;
   233→}
   234→.faq-item summary::-webkit-details-marker { display: none; }
   235→.faq-item summary::after {
   236→  content: '+'; font-size: 28px; font-weight: 300;
   237→  color: var(--gray); transition: transform 0.3s ease;
   238→}
   239→.faq-item details[open] summary::after { transform: rotate(45deg); }
   240→.faq-item .faq-answer { padding-bottom: 32px; font-size: 16px; color: var(--gray); line-height: 1.6; }
   241→
   242→/* CTA SECTION */
   243→.cta-section {
   244→  padding: 160px 0; text-align: center; position: relative;
   245→  background: var(--cream);
   246→}
   247→.cta-section::before {
   248→  content: ''; position: absolute; top: 50%; left: 50%;
   249→  transform: translate(-50%, -50%);
   250→  width: 500px; height: 500px;
   251→  background: radial-gradient(circle, rgba(61,90,252,0.06) 0%, transparent 70%);
   252→  pointer-events: none;
   253→}
   254→.cta-section h2 {
   255→  font-size: clamp(36px, 5vw, 60px); font-weight: 700;
   256→  letter-spacing: -1.5px; margin-bottom: 20px; line-height: 1.1;
   257→}
   258→.cta-section p { font-size: 18px; color: var(--gray); margin-bottom: 40px; font-weight: 300; }
   259→
   260→/* FOOTER */
   261→footer { background: #1c1b1a; color: #f5f2eb; padding: 60px 0 40px; }
   262→.footer-grid { display: grid; grid-template-columns: 2fr 1fr 1fr 1fr; gap: 48px; margin-bottom: 60px; }
   263→.footer-brand p { color: #8a8780; font-size: 14px; margin-top: 12px; max-width: 280px; line-height: 1.6; }
   264→.footer-col h4 { font-size: 13px; text-transform: uppercase; letter-spacing: 1.5px; color: #8a8780; margin-bottom: 16px; font-family: var(--font-display); }
   265→.footer-col a { display: block; font-size: 14px; color: #c4c1b8; padding: 4px 0; transition: color 0.2s; }
   266→.footer-col a:hover { color: #f5f2eb; }
   267→.footer-bottom { border-top: 1px solid rgba(245,242,235,0.08); padding-top: 24px; display: flex; justify-content: space-between; align-items: center; color: #8a8780; font-size: 13px; }
   268→
   269→/* RESPONSIVE */
   270→@media (max-width: 768px) {
   271→  section { padding: 80px 0; }
   272→  .hero { min-height: auto; padding-top: 120px; padding-bottom: 60px; }
   273→  .hero h1 { font-size: 40px; letter-spacing: -1px; }
   274→  .nav-links { display: none; }
   275→  .footer-grid { grid-template-columns: 1fr 1fr; }
   276→  .hero-meta { gap: 20px; }
   277→  .timeline-item { gap: 16px; }
   278→}
   279→
   280→/* ANIMATIONS */
   281→.fade-up { opacity: 0; transform: translateY(30px); transition: opacity 0.7s ease, transform 0.7s ease; }
   282→.fade-up.visible { opacity: 1; transform: translateY(0); }
   283→</style>
   284→</head>
   285→<body>
   286→
   287→<nav>
   288→  <div class="container">
   289→    <a href="index.html" class="logo">[Habitat]</a>
   290→    <ul class="nav-links">
   291→      <li><a href="https://luma.com/habitat" target="_blank">Events</a></li>
   292→      <li><a href="hackathon.html" class="active">Hackathons</a></li>
   293→      <li><a href="residency.html">Residency</a></li>
   294→      <li><a href="index.html#why">Why Habitat</a></li>
   295→      <li><a href="contact.html" class="nav-cta">Join waitlist &rarr;</a></li>
   296→    </ul>
   297→  </div>
   298→</nav>
   299→
   300→<!-- HERO -->
   301→<section class="hero">
   302→  <div class="container">
   303→    <div class="hero-label">Technical Hackathons</div>
   304→    <h1>One day. One team.<br><em>One working product.</em></h1>
   305→    <p class="hero-sub">Full-day deep builds for developers and technical founders. Real infrastructure. Real stakes. Ship or learn — either way you win.</p>
   306→    <div class="hero-meta">
   307→      <div class="hero-meta-item">
   308→        <span class="hero-meta-label">Duration</span>
   309→        <span class="hero-meta-value">10am – 8pm</span>
   310→      </div>
   311→      <div class="hero-meta-item">
   312→        <span class="hero-meta-label">Team size</span>
   313→        <span class="hero-meta-value">2-3 people</span>
   314→      </div>
   315→
   316→      <div class="hero-meta-item">
   317→        <span class="hero-meta-label">Output</span>
   318→        <span class="hero-meta-value">Working demo</span>
   319→      </div>
   320→    </div>
   321→    <div class="hero-buttons">
   322→      <a href="contact.html?program=hackathon" class="btn-primary">Register interest &rarr;</a>
   323→      <a href="#format" class="btn-secondary">See the format</a>
   324→    </div>
   325→  </div>
   326→</section>
   327→
   328→<!-- FORMAT -->
   329→<section class="format-section" id="format">
   330→  <div class="container">
   331→    <div class="section-label fade-up">The format</div>
   332→    <h2 class="section-title fade-up">10 hours of focused building.</h2>
   333→    <p class="section-sub fade-up">No slides. No pitch decks at the start. You arrive, you form a team, you build. At the end, you demo a working product to the investors in the room.</p>
   334→
   335→    <div class="timeline fade-up">
   336→      <div class="timeline-item">
   337→        <div class="timeline-time">10:00</div>
   338→        <div class="timeline-dot"><div class="timeline-dot-circle"></div><div class="timeline-dot-line"></div></div>
   339→        <div class="timeline-content">
   340→          <h3>Kickoff &amp; theme reveal</h3>
   341→          <p>The technical theme or problem space is announced. Team up, pick your angle, define your scope. You have 30 minutes to align — then you build.</p>
   342→        </div>
   343→      </div>
   344→      <div class="timeline-item">
   345→        <div class="timeline-time">10:30</div>
   346→        <div class="timeline-dot"><div class="timeline-dot-circle"></div><div class="timeline-dot-line"></div></div>
   347→        <div class="timeline-content">
   348→          <h3>Building begins</h3>
   349→          <p>Heads down. Real code, real infrastructure, real product. Experienced mentors are in the room to unblock you when you're stuck.</p>
   350→        </div>
   351→      </div>
   352→      <div class="timeline-item">
   353→        <div class="timeline-time">13:00</div>
   354→        <div class="timeline-dot"><div class="timeline-dot-circle"></div><div class="timeline-dot-line"></div></div>
   355→        <div class="timeline-content">
   356→          <h3>Lunch + mid-day check-in</h3>
   357→          <p>Break, eat, recalibrate. Optional 5-minute mid-day check-ins with a mentor if you've hit a wall or want to pressure-test your approach.</p>
   358→        </div>
   359→      </div>
   360→      <div class="timeline-item">
   361→        <div class="timeline-time">14:00</div>
   362→        <div class="timeline-dot"><div class="timeline-dot-circle"></div><div class="timeline-dot-line"></div></div>
   363→        <div class="timeline-content">
   364→          <h3>Back to building</h3>
   365→          <p>Afternoon block. Focus on making it work end-to-end, not just look good. A working demo matters more than a polished UI.</p>
   366→        </div>
   367→      </div>
   368→      <div class="timeline-item">
   369→        <div class="timeline-time">18:00</div>
   370→        <div class="timeline-dot"><div class="timeline-dot-circle"></div><div class="timeline-dot-line"></div></div>
   371→        <div class="timeline-content">
   372→          <h3>Freeze + prep demos</h3>
   373→          <p>Code freeze. Two hours to prep your demo — no new features, just make it presentable and tell the story clearly.</p>
   374→        </div>
   375→      </div>
   376→      <div class="timeline-item">
   377→        <div class="timeline-time">19:00</div>
   378→        <div class="timeline-dot"><div class="timeline-dot-circle"></div><div class="timeline-dot-line"></div></div>
   379→        <div class="timeline-content">
   380→          <h3>Demo + pitches</h3>
   381→          <p>Each team gets 5 minutes. Live demo, one slide max. Mentors and peers ask real questions. The best teams get follow-up conversations, not just a prize.</p>
   382→        </div>
   383→      </div>
   384→      <div class="timeline-item">
   385→        <div class="timeline-time">20:00</div>
   386→        <div class="timeline-dot"><div class="timeline-dot-circle"></div><div class="timeline-dot-line"></div></div>
   387→        <div class="timeline-content">
   388→          <h3>Awards + networking</h3>
   389→          <p>Prizes, credits, and introductions. More importantly: the people in this room are who you want to know.</p>
   390→        </div>
   391→      </div>
   392→    </div>
   393→  </div>
   394→</section>
   395→
   396→<!-- WHO ATTENDS -->
   397→<section>
   398→  <div class="container">
   399→    <div class="section-label fade-up">Who attends</div>
   400→    <h2 class="section-title fade-up">Built for people who ship.</h2>
   401→    <p class="section-sub fade-up">This isn't a general hackathon. We select for technical ability and the drive to build real things — not to win competitions.</p>
   402→
   403→    <div class="who-grid">
   404→      <div class="who-card fade-up">
   405→        <div class="who-card-icon">⚡</div>
   406→        <h3>Technical founders</h3>
   407→        <p>You've already shipped something. You build fast. You want a focused day with peers at your level and direct access to investors who get technical products.</p>
   408→      </div>
   409→      <div class="who-card fade-up">
   410→        <div class="who-card-icon">🛠</div>
   411→        <h3>Developers exploring startups</h3>
   412→        <p>You're a strong engineer who's been thinking about building your own thing. This is a low-stakes way to test if you like the founder experience.</p>
   413→      </div>
   414→      <div class="who-card fade-up">
   415→        <div class="who-card-icon">🎓</div>
   416→        <h3>CS &amp; engineering students</h3>
   417→        <p>From KU Leuven, UGent, VUB, or elsewhere. You want to build something real, meet people who are doing it, and get in front of investors early.</p>
   418→      </div>
   419→    </div>
   420→  </div>
   421→</section>
   422→
   423→
   424→
   425→<!-- WHAT YOU BUILD -->
   426→<section>
   427→  <div class="container">
   428→    <div class="section-label fade-up">What you walk away with</div>
   429→    <h2 class="section-title fade-up">More than a weekend project.</h2>
   430→    <p class="section-sub fade-up">The goal isn't to win a hackathon. The goal is to leave with something worth continuing — and people worth building with.</p>
   431→
   432→    <div class="output-grid">
   433→      <div class="output-item fade-up">
